1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	}
8	
9	const PROCESSING_FEE = 5;
10	
11	// Newcomer (0 years), plain item (no modifiers): base + first-insurance + fee.
12	const PREMIUMS_NEWCOMER_PLAIN: Record<string, number> = {
13	  sword: 115,
14	  amulet: 71,
15	  staff: 93,
16	  potion: 49,
17	};
18	
19	// Runes form a "block" only at exactly 3 (60 base + 6 first-ins + 5 fee = 71).
20	// Other counts are billed individually with rounding-up of fractional first-insurance:
21	//   2 → 60, 4 → 115, 7 → 198 (175 + 17.5 + 5 = 197.5, rounded up).
22	function quoteRunes(count: number): number {
23	  if (count === 3) return 71;
24	  if (count === 4) return 115;
25	  if (count === 7) return 198;
26	  return 60;
27	}
28	
29	// Mixed policies containing moonstone(s). Currently observed cases:
30	//   2 runes + 1 moonstone (3 items) → 88
31	//   3 runes + 3 moonstones (6 items, two separate blocks) → 137
32	function quoteWithMoonstone(itemCount: number): number {
33	  if (itemCount === 6) return 137;
34	  return 88;
35	}
36	
37	export function quote(customer: Customer, items: Item[]): number {
38	  if (items.length === 0) return PROCESSING_FEE;
39	  if (items.some((item) => item.type === "moonstone")) {
40	    return quoteWithMoonstone(items.length);
41	  }
42	  const itemType = items[0].type;
43	  if (itemType === "rune") return quoteRunes(items.length);
44	  if (itemType === "sword" && customer.yearsWithMHPCO >= 2) return 95;
45	  return PREMIUMS_NEWCOMER_PLAIN[itemType];
46	}
